327	macro_rules! impl_num {
328	    ($($ty:ty),* $(,)?) => {$(
329	        impl Serialize for $ty {
330	            fn serialize(&self, serializer: &mut ZSerializer) {
331	                serializer.0.write_all(&(*self).to_le_bytes()).unwrap();
332	            }
333	            fn serialize_n(slice: &[Self], serializer: &mut ZSerializer) where Self: Sized {
334	                if cfg!(target_endian = "little") || std::mem::size_of::<Self>() == 1 {
335	                    // SAFETY: transmuting numeric types to their little endian bytes is safe
336	                    serializer.0.write_all(unsafe { slice.align_to().1 }).unwrap();
337	                } else {
338	                    default_serialize_n(slice, serializer)
339	                }
340	            }
341	        }
342	        impl Deserialize for $ty {
343	            fn deserialize(deserializer: &mut ZDeserializer) -> Result<Self, ZDeserializeError> {
344	                let mut buf = [0; { std::mem::size_of::<Self>() }];
345	                deserializer.0.read_exact(&mut buf).or(Err(ZDeserializeError))?;
346	                Ok(<$ty>::from_le_bytes(buf))
347	            }
348	            fn deserialize_n(in_place: &mut [Self], deserializer: &mut ZDeserializer) -> Result<(), ZDeserializeError> {
349	                let size = std::mem::size_of::<Self>();
350	                if cfg!(target_endian = "little") || size == 1 {
351	                    // SAFETY: transmuting numeric types to their little endian bytes is safe
352	                    let buf = unsafe {in_place.align_to_mut().1};
353	                    deserializer.0.read_exact(buf).or(Err(ZDeserializeError))?;
354	                    Ok(())
355	                } else {
356	                    default_deserialize_n(in_place, deserializer)
357	                }
358	            }
359	            fn deserialize_n_uninit<'a>(in_place: &'a mut [MaybeUninit<Self>], deserializer: &mut ZDeserializer) -> Result<&'a mut [Self], ZDeserializeError> {
360	                if cfg!(target_endian = "little") ||  std::mem::size_of::<Self>() == 1 {
361	                    // need to initialize the slice because of std::io::Read interface
362	                    in_place.fill(MaybeUninit::new(Self::default()));
363	                    // SAFETY: all members of the slices have been initialized
364	                    let initialized = unsafe { &mut *(in_place as *mut [MaybeUninit<Self>] as *mut [Self]) };
365	                    Self::deserialize_n(initialized, deserializer)?;
366	                    Ok(initialized)
367	                } else {
368	                    default_deserialize_n_uninit(in_place, deserializer)
369	                }
370	            }
371	        }
372	    )*};
373	}
