391	fn serialize_slice<T: Serialize>(slice: &[T], serializer: &mut ZSerializer) {
392	    serializer.serialize(VarInt(slice.len()));
393	    T::serialize_n(slice, serializer);
394	}
395	
396	fn deserialize_slice<T: Deserialize>(
397	    deserializer: &mut ZDeserializer,
398	) -> Result<Box<[T]>, ZDeserializeError> {
399	    let len = <VarInt<usize>>::deserialize(deserializer)?.0;
400	    let mut vec = Vec::with_capacity(len);
401	    let slice = T::deserialize_n_uninit(&mut vec.spare_capacity_mut()[..len], deserializer)?;
402	    let (slice_ptr, slice_len) = (slice.as_ptr(), slice.len());
403	    assert_eq!((slice_ptr, slice_len), (vec.as_ptr(), len));
404	    // SAFETY: assertion checks the returned slice is vector's one, and it's returned initialized
405	    unsafe { vec.set_len(len) };
406	    Ok(vec.into_boxed_slice())
407	}
