566	/// The [LEB128](https://en.wikipedia.org/wiki/LEB128) variable-length integer encoding.
567	///
568	/// The `zenoh-ext` implements serialization and deserialization of integers in variable-length `LEB128` format.
569	/// Currently it's implemented for `usize` only using the wrapper struct `VarInt<usize>`:
570	/// the traits [`Serialize`] and [`Deserialize`] are implemented for `VarInt<usize>` using
571	/// [leb128](https://crates.io/crates/leb128) crate.
572	///
573	/// This is used internally for serializing lengths of sequences (slices, `Vec`, `String`, `HashMap`, etc)
574	/// and could be used by users to serialize integer values in a more compact way.
575	#[repr(transparent)]
576	#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
577	pub struct VarInt<T>(pub T);
578	impl Serialize for VarInt<usize> {
579	    fn serialize(&self, serializer: &mut ZSerializer) {
580	        leb128::write::unsigned(&mut serializer.0, self.0 as u64).unwrap();
581	    }
582	}
583	impl Deserialize for VarInt<usize> {
584	    fn deserialize(deserializer: &mut ZDeserializer) -> Result<Self, ZDeserializeError> {
585	        let n = leb128::read::unsigned(&mut deserializer.0).or(Err(ZDeserializeError))?;
586	        Ok(VarInt(<usize>::try_from(n).or(Err(ZDeserializeError))?))
587	    }
588	}
