591	mod tests {
592	    use std::ops::Range;
593	
594	    use rand::{thread_rng, Rng};
595	
596	    use super::*;
597	
598	    macro_rules! serialize_deserialize {
599	        ($ty:ty, $expr:expr) => {
600	            let expr: &$ty = &$expr;
601	            let payload = z_serialize(expr);
602	            let output = z_deserialize::<$ty>(&payload).unwrap();
603	            assert_eq!(*expr, output);
604	        };
605	    }
606	
607	    const RANDOM_TESTS: Range<usize> = 0..1_000;
608	
609	    #[test]
610	    fn numeric_serialization() {
611	        macro_rules! test_int {
612	            ($($ty:ty),* $(,)?) => {$(
613	                serialize_deserialize!($ty, <$ty>::MIN);
614	                serialize_deserialize!($ty, <$ty>::MAX);
615	                let mut rng = thread_rng();
616	                for _ in RANDOM_TESTS {
617	                    serialize_deserialize!($ty, rng.gen::<$ty>());
618	                }
619	            )*};
620	        }
621	        test_int!(i8, i16, i32, i64, i128, u8, u16, u32, u64, u128, f32, f64);
622	    }
623	
624	    #[test]
625	    fn varint_serialization() {
626	        serialize_deserialize!(VarInt<usize>, VarInt(<usize>::MIN));
627	        serialize_deserialize!(VarInt<usize>, VarInt(<usize>::MAX));
628	        let mut rng = thread_rng();
629	        for _ in RANDOM_TESTS {
630	            serialize_deserialize!(VarInt<usize>, VarInt(rng.gen::<usize>()));
631	        }
632	    }
633	
634	    #[test]
635	    fn primitive_slice_serialization() {
636	        let vec = vec![42.0f64, 0.15];
637	        serialize_deserialize!(Vec<f64>, vec);
638	        let payload = z_serialize(vec.as_slice());
639	        assert_eq!(vec, z_deserialize::<Vec<f64>>(&payload).unwrap())
640	    }
641	
642	    #[test]
643	    fn slice_serialization() {
644	        let vec = vec!["abc".to_string(), "def".to_string()];
645	        serialize_deserialize!(Vec<String>, vec);
646	        let payload = z_serialize(vec.as_slice());
647	        assert_eq!(vec, z_deserialize::<Vec<String>>(&payload).unwrap())
648	    }
649	
650	    #[test]
651	    fn string_serialization() {
652	        let s = "serialization".to_string();
653	        serialize_deserialize!(String, s);
654	        let payload = z_serialize(s.as_str());
655	        assert_eq!(s, z_deserialize::<String>(&payload).unwrap())
656	    }
