694	                4, 156, 255, 255, 255, 255, 255, 255, 255, 244, 1, 0, 0, 0, 0, 0, 0, 160, 134, 1,
695	                0, 0, 0, 0, 0, 0, 211, 206, 254, 255, 255, 255, 255
696	            ]
697	        );
698	        let vp: Vec<(&str, i16)> = vec![("s1", 10), ("s2", -10000)];
699	        check_binary_format!(vp, vec![2, 2, 115, 49, 10, 0, 2, 115, 50, 240, 216]);
