6	use serde_json::json;
7	use zenoh::{config::WhatAmI, Config};
8	
9	#[derive(clap::Parser, Clone, PartialEq, Eq, Hash, Debug)]
10	pub struct CommonArgs {
11	    #[arg(short, long)]
12	    /// A configuration file.
13	    config: Option<String>,
14	    #[arg(long)]
15	    /// Allows arbitrary configuration changes as column-separated KEY:VALUE pairs, where:
16	    ///   - KEY must be a valid config path.
17	    ///   - VALUE must be a valid JSON5 string that can be deserialized to the expected type for the KEY field.
18	    ///
19	    /// Example: `--cfg='transport/unicast/max_links:2'`
20	    #[arg(long)]
21	    cfg: Vec<String>,
22	    #[arg(short, long)]
23	    /// The Zenoh session mode [default: peer].
24	    mode: Option<WhatAmI>,
25	    #[arg(short = 'e', long)]
26	    /// Endpoints to connect to.
27	    connect: Vec<String>,
28	    #[arg(short, long)]
29	    /// Endpoints to listen on.
30	    listen: Vec<String>,
31	    #[arg(long)]
32	    /// Disable the multicast-based scouting mechanism.
33	    no_multicast_scouting: bool,
34	    #[arg(long)]
35	    /// Enable shared-memory feature.
36	    enable_shm: bool,
37	}
38	
39	impl From<CommonArgs> for Config {
40	    fn from(value: CommonArgs) -> Self {
41	        (&value).into()
42	    }
43	}
44	
45	impl From<&CommonArgs> for Config {
46	    fn from(args: &CommonArgs) -> Self {
47	        let mut config = match &args.config {
48	            Some(path) => Config::from_file(path).unwrap(),
49	            None => Config::default(),
50	        };
51	        if let Some(mode) = args.mode {
52	            config
53	                .insert_json5("mode", &json!(mode.to_str()).to_string())
54	                .unwrap();
55	        }
56	
57	        if !args.connect.is_empty() {
58	            config
59	                .insert_json5("connect/endpoints", &json!(args.connect).to_string())
60	                .unwrap();
61	        }
62	        if !args.listen.is_empty() {
63	            config
64	                .insert_json5("listen/endpoints", &json!(args.listen).to_string())
65	                .unwrap();
66	        }
67	        if args.no_multicast_scouting {
68	            config
69	                .insert_json5("scouting/multicast/enabled", &json!(false).to_string())
70	                .unwrap();
71	        }
72	        if args.enable_shm {
73	            #[cfg(feature = "shared-memory")]
74	            config
75	                .insert_json5("transport/shared_memory/enabled", &json!(true).to_string())
76	                .unwrap();
77	            #[cfg(not(feature = "shared-memory"))]
78	            {
79	                eprintln!("`--enable-shm` argument: SHM cannot be enabled, because Zenoh is compiled without shared-memory feature!");
80	                std::process::exit(-1);
81	            }
82	        }
83	        for json in &args.cfg {
84	            if let Some((key, value)) = json.split_once(':') {
85	                if let Err(err) = config.insert_json5(key, value) {
86	                    eprintln!("`--cfg` argument: could not parse `{json}`: {err}");
87	                    std::process::exit(-1);
88	                }
89	            } else {
90	                eprintln!("`--cfg` argument: expected KEY:VALUE pair, got {json}");
91	                std::process::exit(-1);
92	            }
93	        }
94	        config
95	    }
96	}
