60	/// Configuration for sample miss detection
61	///
62	/// Enabling [`sample_miss_detection`](crate::AdvancedPublisherBuilder::sample_miss_detection) in [`AdvancedPublisher`](crate::AdvancedPublisher)
63	/// allows [`AdvancedSubscribers`](crate::AdvancedSubscriber) to detect missed samples
64	/// through [`sample_miss_listener`](crate::AdvancedSubscriber::sample_miss_listener)
65	/// and to recover missed samples through [`recovery`](crate::AdvancedSubscriberBuilder::recovery).
66	#[zenoh_macros::unstable]
67	#[derive(Debug, Default, Clone)]
68	pub struct MissDetectionConfig {
69	    pub(crate) state_publisher: Option<(Duration, bool)>,
70	}
71	
72	#[zenoh_macros::unstable]
73	impl MissDetectionConfig {
74	    /// Allow last sample miss detection through periodic heartbeat.
75	    ///
76	    /// Periodically send the last published sample's sequence number to allow last sample recovery.
77	    ///
78	    /// [`heartbeat`](MissDetectionConfig::heartbeat) and [`sporadic_heartbeat`](MissDetectionConfig::sporadic_heartbeat)
79	    /// are mutually exclusive. Enabling one will disable the other.
80	    ///
81	    /// [`AdvancedSubscribers`](crate::AdvancedSubscriber) can recover last sample with the
82	    /// [`heartbeat`](crate::advanced_subscriber::RecoveryConfig::heartbeat) option.
83	    #[zenoh_macros::unstable]
84	    pub fn heartbeat(mut self, period: Duration) -> Self {
85	        self.state_publisher = Some((period, false));
86	        self
87	    }
88	
89	    /// Allow last sample miss detection through sporadic heartbeat.
90	    ///
91	    /// Each period, the last published sample's sequence number is sent with [`CongestionControl::Block`]
92	    /// but only if it changed since the last period.
93	    ///
94	    /// [`heartbeat`](MissDetectionConfig::heartbeat) and [`sporadic_heartbeat`](MissDetectionConfig::sporadic_heartbeat)
95	    /// are mutually exclusive. Enabling one will disable the other.
96	    ///
97	    /// [`AdvancedSubscribers`](crate::AdvancedSubscriber) can recover last sample with the
98	    /// [`heartbeat`](crate::advanced_subscriber::RecoveryConfig::heartbeat) option.
99	    #[zenoh_macros::unstable]
100	    pub fn sporadic_heartbeat(mut self, period: Duration) -> Self {
101	        self.state_publisher = Some((period, true));
102	        self
103	    }
104	}
