305	/// The extension to a [`Publisher`](zenoh::pubsub::Publisher) providing advanced functionalities.
306	///
307	/// The `AdvancedPublisher` is constructed over a regular [`Publisher`](zenoh::pubsub::Publisher) through
308	/// [`advanced`](crate::AdvancedPublisherBuilderExt::advanced) method or by using
309	/// any other method of [`AdvancedPublisherBuilder`](crate::AdvancedPublisherBuilder).
310	///
311	/// The `AdvancedPublisher` works with [`AdvancedSubscriber`](crate::AdvancedSubscriber) to provide additional functionalities such as:
312	/// - [`cache`](crate::AdvancedPublisherBuilderExt::cache) last published samples to be retrieved by
313	///   [`AdvancedSubscriber`](crate::AdvancedSubscriber)'s [`history`](crate::AdvancedSubscriberBuilderExt::history) mechanism
314	/// - [`sample_miss_detection`](crate::AdvancedPublisherBuilderExt::sample_miss_detection) to allow detecting missed samples
315	///   using [`AdvancedSubscriber`](crate::AdvancedSubscriber)'s [`sample_miss_listener`](crate::AdvancedSubscriber::sample_miss_listener)
316	/// - [`publisher_detection`](crate::AdvancedPublisherBuilderExt::publisher_detection) to create a Liveliness token to assert its presence and
317	///   allow it to be requested for missed samples if [`detect_late_publishers`](crate::HistoryConfig::detect_late_publishers) is enabled
318	///
319	/// # Example
320	/// ```no_run
321	/// # #[tokio::main]
322	/// # async fn main() {
323	/// use zenoh_ext::{AdvancedPublisherBuilderExt, CacheConfig, MissDetectionConfig};
324	/// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
325	/// let publisher = session
326	///     .declare_publisher("key/expression")
327	///     .cache(CacheConfig::default().max_samples(10))
328	///     .sample_miss_detection(
329	///         MissDetectionConfig::default().heartbeat(std::time::Duration::from_secs(1))
330	///     )
331	///     .publisher_detection()
332	///     .await
333	///     .unwrap();
334	/// publisher.put("Value").await.unwrap();
335	/// # }
336	/// ```
337	#[zenoh_macros::unstable]
338	pub struct AdvancedPublisher<'a> {
339	    publisher: Publisher<'a>,
340	    seqnum: Option<Arc<AtomicU32>>,
341	    cache: Option<AdvancedCache>,
342	    _token: Option<LivelinessToken>,
343	    _state_publisher: Option<TerminatableTask>,
344	}
345	
346	#[zenoh_macros::unstable]
347	impl fmt::Debug for AdvancedPublisher<'_> {
348	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
349	        f.debug_struct("AdvancedPublisher")
350	            .field("publisher", &self.publisher)
351	            .field(
352	                "seqnum",
353	                &self
354	                    .seqnum
355	                    .as_ref()
356	                    .map(|seqnum| seqnum.load(Ordering::Relaxed)),
357	            )
358	            .field("cache", &self.cache.as_ref().map(|_| ".."))
359	            .field("token", &self._token.as_ref().map(|_| ".."))
360	            .field("state_publisher", &self._state_publisher)
