365	#[zenoh_macros::unstable]
366	impl<'a> AdvancedPublisher<'a> {
367	    #[zenoh_macros::unstable]
368	    fn new(conf: AdvancedPublisherBuilder<'_, 'a, '_>) -> ZResult<Self> {
369	        let key_expr = conf.pub_key_expr?;
370	        let meta = match conf.meta_key_expr {
371	            Some(meta) => Some(meta?),
372	            None => None,
373	        };
374	        tracing::debug!("Create AdvancedPublisher{{key_expr: {}}}", &key_expr);
375	
376	        let publisher = conf
377	            .session
378	            .declare_publisher(key_expr.clone())
379	            .encoding(conf.encoding)
380	            .allowed_destination(conf.destination)
381	            .reliability(conf.reliability)
382	            .congestion_control(conf.congestion_control)
383	            .priority(conf.priority)
384	            .express(conf.is_express)
385	            .wait()?;
386	        let id = publisher.id();
387	        let suffix = KE_ADV_PREFIX / KE_PUB / &id.zid().into_keyexpr();
388	        let suffix = match conf.sequencing {
389	            Sequencing::SequenceNumber => {
390	                suffix / &KeyExpr::try_from(id.eid().to_string()).unwrap()
391	            }
392	            _ => suffix / KE_UHLC,
393	        };
394	        let suffix = match meta {
395	            Some(meta) => suffix / &meta,
396	            // We need this empty chunk because of a routing matching bug
397	            _ => suffix / KE_EMPTY,
398	        };
399	
400	        let seqnum = match conf.sequencing {
401	            Sequencing::SequenceNumber => Some(Arc::new(AtomicU32::new(0))),
402	            Sequencing::Timestamp => {
403	                if conf.session.hlc().is_none() {
404	                    bail!(
405	                        "Cannot create AdvancedPublisher {} with Sequencing::Timestamp: \
406	                            the 'timestamping' setting must be enabled in the Zenoh configuration.",
407	                        key_expr,
408	                    )
409	                }
410	                None
411	            }
412	            _ => None,
413	        };
414	
415	        let cache = conf
416	            .history
417	            .map(|h| {
418	                AdvancedCacheBuilder::new(conf.session, Ok(key_expr.clone()))
419	                    .history(h)
420	                    .queryable_suffix(&suffix)
421	                    .wait()
422	            })
423	            .transpose()?;
424	
425	        let token = if conf.liveliness {
426	            tracing::debug!(
427	                "AdvancedPublisher{{key_expr: {}}}: Declare liveliness token {}",
428	                key_expr,
429	                &key_expr / &suffix,
430	            );
431	            Some(
432	                conf.session
433	                    .liveliness()
434	                    .declare_token(&key_expr / &suffix)
435	                    .wait()?,
436	            )
437	        } else {
438	            None
439	        };
440	
441	        let state_publisher = if let Some((period, sporadic)) =
442	            conf.miss_config.as_ref().and_then(|c| c.state_publisher)
443	        {
444	            if let Some(seqnum) = seqnum.as_ref() {
445	                tracing::debug!(
446	                    "AdvancedPublisher{{key_expr: {}}}: Enable {}heartbeat on {} with period {:?}",
447	                    key_expr,
448	                    if sporadic { "sporadic " } else { "" },
449	                    &key_expr / &suffix,
450	                    period
451	                );
452	                let seqnum = seqnum.clone();
453	                if !sporadic {
454	                    let publisher = conf.session.declare_publisher(&key_expr / &suffix).wait()?;
455	                    Some(TerminatableTask::spawn_abortable(
456	                        ZRuntime::Net,
457	                        async move {
458	                            loop {
459	                                tokio::time::sleep(period).await;
460	                                let seqnum = seqnum.load(Ordering::Relaxed);
461	                                if seqnum > 0 {
462	                                    let _ = publisher.put(z_serialize(&(seqnum - 1))).await;
463	                                }
464	                            }
465	                        },
466	                    ))
467	                } else {
468	                    let mut last_seqnum = 0;
469	                    let publisher = conf
470	                        .session
471	                        .declare_publisher(&key_expr / &suffix)
472	                        .congestion_control(CongestionControl::Block)
473	                        .wait()?;
474	                    Some(TerminatableTask::spawn_abortable(
475	                        ZRuntime::Net,
476	                        async move {
477	                            loop {
478	                                tokio::time::sleep(period).await;
479	                                let seqnum = seqnum.load(Ordering::Relaxed);
480	                                if seqnum > last_seqnum {
481	                                    let _ = publisher.put(z_serialize(&(seqnum - 1))).await;
482	                                    last_seqnum = seqnum;
483	                                }
484	                            }
485	                        },
486	                    ))
487	                }
488	            } else {
489	                None
490	            }
491	        } else {
492	            None
493	        };
494	
495	        Ok(AdvancedPublisher {
496	            publisher,
497	            seqnum,
498	            cache,
499	            _token: token,
500	            _state_publisher: state_publisher,
501	        })
502	    }
