548	    /// Put data.
549	    ///
550	    /// Wraps [`Publisher::put`](zenoh::pubsub::Publisher::put) method
551	    ///
552	    /// # Examples
553	    /// ```
554	    /// # #[tokio::main]
555	    /// # async fn main() {
556	    /// use zenoh_ext::AdvancedPublisherBuilderExt;
557	    ///
558	    /// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
559	    /// let publisher = session.declare_publisher("key/expression").advanced().await.unwrap();
560	    /// publisher.put("value").await.unwrap();
561	    /// # }
562	    /// ```
563	    #[inline]
564	    #[zenoh_macros::unstable]
565	    pub fn put<IntoZBytes>(&self, payload: IntoZBytes) -> AdvancedPublisherPutBuilder<'_>
566	    where
567	        IntoZBytes: Into<ZBytes>,
568	    {
569	        let mut builder = self.publisher.put(payload);
570	        if let Some(seqnum) = &self.seqnum {
571	            let info = Some(SourceInfo::new(
572	                self.publisher.id(),
573	                seqnum.fetch_add(1, Ordering::Relaxed),
574	            ));
575	            tracing::trace!(
576	                "AdvancedPublisher{{key_expr: {}}}: Put data with {:?}",
577	                self.publisher.key_expr(),
578	                info
579	            );
580	            builder = builder.source_info(info);
581	        }
582	        if let Some(hlc) = self.publisher.session().hlc() {
583	            builder = builder.timestamp(hlc.new_timestamp());
584	        }
585	        AdvancedPublisherPutBuilder {
586	            builder,
587	            cache: self.cache.as_ref(),
588	        }
589	    }
