592	    ///
593	    /// Wraps [`Publisher::delete`](zenoh::pubsub::Publisher::delete) method
594	    ///
595	    /// # Examples
596	    /// ```
597	    /// # #[tokio::main]
598	    /// # async fn main() {
599	    /// use zenoh_ext::AdvancedPublisherBuilderExt;
