606	    #[zenoh_macros::unstable]
607	    pub fn delete(&self) -> AdvancedPublisherDeleteBuilder<'_> {
608	        let mut builder = self.publisher.delete();
609	        if let Some(seqnum) = &self.seqnum {
610	            builder = builder.source_info(Some(SourceInfo::new(
611	                self.publisher.id(),
612	                seqnum.fetch_add(1, Ordering::Relaxed),
613	            )));
614	        }
615	        if let Some(hlc) = self.publisher.session().hlc() {
616	            builder = builder.timestamp(hlc.new_timestamp());
617	        }
618	        AdvancedPublisherDeleteBuilder {
619	            builder,
620	            cache: self.cache.as_ref(),
621	        }
622	    }
