525	/// The extension to [`Subscriber`](zenoh::pubsub::Subscriber) that provides advanced functionalities
526	///
527	/// The `AdvancedSubscriber` is constructed over a regular [`Subscriber`](zenoh::pubsub::Subscriber)
528	/// through [`advanced`](crate::AdvancedSubscriberBuilderExt::advanced) method or by using
529	/// any other method of [`AdvancedSubscriberBuilder`](crate::AdvancedSubscriberBuilder).
530	///
531	/// The `AdvancedSubscriber` works with [`AdvancedPublisher`](crate::AdvancedPublisher) to provide additional functionalities such as:
532	/// * missing samples detection using periodic queries or heartbeat subscription configurable with [`recovery`](crate::AdvancedSubscriberBuilder::recovery) method
533	/// * recovering missing samples, configured with [`history`](crate::AdvancedSubscriberBuilder::history) method
534	///   (max age and sample count, late joiner detection and requesting)
535	/// * liveliness-based subscriber detection with [`subscriber_detection`](crate::AdvancedSubscriberBuilder::subscriber_detection) method
536	///
537	/// # Examples
538	/// ```no_run
539	/// # #[tokio::main]
540	/// # async fn main() {
541	/// use zenoh_ext::{AdvancedSubscriberBuilderExt, HistoryConfig, RecoveryConfig};
542	/// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
543	/// let subscriber = session
544	///     .declare_subscriber("key/expression")
545	///     .history(HistoryConfig::default().detect_late_publishers())
546	///     .recovery(RecoveryConfig::default().heartbeat())
547	///     .subscriber_detection()
548	///     .await
549	///     .unwrap();
550	/// let miss_listener = subscriber.sample_miss_listener().await.unwrap();
551	/// loop {
552	///     tokio::select! {
553	///         sample = subscriber.recv_async() => {
554	///             if let Ok(sample) = sample {
555	///                 // ...
556	///             }
557	///         },
558	///         miss = miss_listener.recv_async() => {
559	///             if let Ok(miss) = miss {
560	///                 // ...
561	///             }
562	///         },
563	///     }
564	/// }
565	/// # }
566	/// ```
567	#[zenoh_macros::unstable]
568	pub struct AdvancedSubscriber<Receiver> {
569	    statesref: Arc<Mutex<State>>,
570	    subscriber: Subscriber<()>,
571	    receiver: Receiver,
572	    liveliness_subscriber: Option<Subscriber<()>>,
573	    heartbeat_subscriber: Option<Subscriber<()>>,
574	}
