604	#[zenoh_macros::unstable]
605	fn handle_sample(states: &mut State, sample: Sample) -> bool {
606	    let Some(callback) = states.callback.as_ref() else {
607	        return false;
608	    };
609	    if let Some(source_info) = sample.source_info().cloned() {
610	        #[inline]
611	        fn deliver_and_flush(
612	            sample: Sample,
613	            source_sn: impl Into<WrappingSn>,
614	            callback: &Callback<Sample>,
615	            state: &mut SourceState<WrappingSn>,
616	        ) {
617	            let mut source_sn = source_sn.into();
618	            callback.call(sample);
619	            state.last_delivered = Some(source_sn);
620	            while let Some(sample) = state.pending_samples.remove(&(source_sn + 1)) {
621	                callback.call(sample);
622	                source_sn += 1;
623	                state.last_delivered = Some(source_sn);
624	            }
625	        }
626	
627	        let mut new = false;
628	        let state = states
629	            .sequenced_states
630	            .get_or_insert_mut(*source_info.source_id(), || {
631	                new = true;
632	                Default::default()
633	            });
634	        if state.last_delivered.is_none() && states.global_pending_queries != 0 {
635	            // Avoid going through the Map if history_depth == 1
636	            if states.max_history_depth == 1 {
637	                state.last_delivered = Some(source_info.source_sn().into());
638	                callback.call(sample);
639	            } else {
640	                state
641	                    .pending_samples
642	                    .insert(source_info.source_sn().into(), sample);
643	                if state.pending_samples.len() >= states.max_history_depth {
644	                    if let Some((sn, sample)) = state.pending_samples.pop_first() {
645	                        deliver_and_flush(sample, sn, callback, state);
646	                    }
647	                }
648	            }
649	        } else if state.last_delivered.is_some()
650	            && source_info.source_sn() != state.last_delivered.unwrap() + 1
651	        {
652	            if source_info.source_sn() > state.last_delivered.unwrap() {
653	                if states.retransmission {
654	                    state
655	                        .pending_samples
656	                        .insert(source_info.source_sn().into(), sample);
657	                } else {
658	                    tracing::info!(
659	                        "Sample missed: missed {} samples from {:?}.",
660	                        source_info.source_sn() - state.last_delivered.unwrap() - 1,
661	                        source_info.source_id(),
662	                    );
663	                    for miss_callback in states.miss_handlers.values() {
664	                        miss_callback.call(Miss {
665	                            source: *source_info.source_id(),
666	                            nb: source_info.source_sn() - state.last_delivered.unwrap() - 1,
667	                        });
668	                    }
669	                    callback.call(sample);
670	                    state.last_delivered = Some(source_info.source_sn().into());
671	                }
672	            }
673	        } else {
674	            deliver_and_flush(sample, source_info.source_sn(), callback, state);
675	        }
676	        state.latest_access = Instant::now();
677	        new
678	    } else if let Some(timestamp) = sample.timestamp() {
679	        let state = states
680	            .timestamped_states
681	            .get_or_insert_mut(*timestamp.get_id(), Default::default);
682	        if state.last_delivered.map(|t| t < *timestamp).unwrap_or(true) {
683	            if (states.global_pending_queries == 0 && state.pending_queries == 0)
684	                || states.max_history_depth == 1
685	            {
686	                state.last_delivered = Some(*timestamp);
687	                callback.call(sample);
688	            } else {
689	                state.pending_samples.entry(*timestamp).or_insert(sample);
690	                if state.pending_samples.len() >= states.max_history_depth {
691	                    flush_timestamped_source(state, Some(callback));
692	                }
693	            }
694	        }
695	        state.latest_access = Instant::now();
696	        false
697	    } else {
698	        callback.call(sample);
699	        false
700	    }
701	}
