704	fn seq_num_range(start: Option<WrappingSn>, end: Option<WrappingSn>) -> String {
705	    match (start, end) {
706	        (Some(start), Some(end)) => format!("_sn={start}..{end}"),
707	        (Some(start), None) => format!("_sn={start}.."),
708	        (None, Some(end)) => format!("_sn=..{end}"),
709	        (None, None) => "_sn=..".to_string(),
710	    }
711	}
712	
713	fn spawn_periodic_queries(
714	    statesref: &Arc<Mutex<State>>,
715	    period: Option<Duration>,
716	    source_id: EntityGlobalId,
717	) -> Option<AbortOnDropHandle<()>> {
718	    let mut interval = tokio::time::interval(period?);
719	    interval.set_missed_tick_behavior(tokio::time::MissedTickBehavior::Skip);
720	    let statesref = statesref.clone();
721	    Some(AbortOnDropHandle::new(ZRuntime::Application.spawn(
722	        async move {
723	            interval.tick().await; // interval first tick is immediate
724	            loop {
725	                interval.tick().await;
726	                periodic_query(&statesref, source_id);
727	            }
728	        },
729	    )))
730	}
731	
732	fn periodic_query(statesref: &Arc<Mutex<State>>, source_id: EntityGlobalId) {
733	    let mut guard = statesref.lock().unwrap();
734	    let states = &mut *guard;
735	    // use peek_mut so query without samples do not prevent the state to be garbage collected
736	    let Some(state) = states.sequenced_states.peek_mut(&source_id) else {
737	        return;
738	    };
739	    state.pending_queries += 1;
740	    let query_expr = &states.key_expr
741	        / KE_ADV_PREFIX
742	        / KE_STAR
743	        / &source_id.zid().into_keyexpr()
744	        / &KeyExpr::try_from(source_id.eid().to_string()).unwrap()
745	        / KE_STARSTAR;
746	    let seq_num_range = seq_num_range(state.last_delivered.map(|s| s + 1), None);
747	
748	    let session = states.session.clone();
