790	/// Garbage collects the source states' lists.
791	///
792	/// Reclamation is based on `SourceState::latest_access`; alive publishers are not reclaimed.
793	async fn gc_task(statesref: Weak<Mutex<State>>, retention_period: Duration) {
794	    /// Garbage collect a lists and return the oldest access.
795	    fn garbage_collect<K: Copy + Eq + Hash, T>(
796	        states: &mut LruCache<K, SourceState<T>>,
797	        retention_period: Duration,
798	        now: Instant,
799	    ) -> Instant {
800	        while let Some((&key, state)) = states.peek_lru() {
801	            if now.duration_since(state.latest_access) <= retention_period {
802	                return state.latest_access;
803	            // if the publisher is still marked as alive, just update its latest access
804	            // (accessing the state will also move it to the back of the LRU list)
805	            } else if state.alive {
806	                states.get_mut(&key).unwrap().latest_access = now;
807	            } else {
808	                states.pop_lru();
809	            }
810	        }
811	        now
812	    }
813	    // start by sleeping for the initial retention period
814	    tokio::time::sleep(retention_period).await;
815	    loop {
816	        let oldest_access = {
817	            let Some(states) = statesref.upgrade() else {
818	                // either the task was scheduled concurrently to its abortion, so we don't care
819	                // sleeping, or we are in the theoretically possible but zero probability case
820	                // of `new_cyclic` not having returned yet, so we still don't care sleeping.
821	                tokio::time::sleep(retention_period).await;
822	                continue;
823	            };
824	            let mut states = states.lock().unwrap();
825	            let now = Instant::now();
826	            min(
827	                garbage_collect(&mut states.sequenced_states, retention_period, now),
828	                garbage_collect(&mut states.timestamped_states, retention_period, now),
829	            )
830	        };
831	        tokio::time::sleep_until((oldest_access + retention_period).into()).await;
832	    }
833	}
