1313	                            heartbeat_keyexpr
1314	                        );
1315	                        return;
1316	                    };
1317	
1318	                    let mut lock = zlock!(statesref);
1319	                    let states = &mut *lock;
1320	                    let mut new = false;
1321	                    let state = states.sequenced_states.get_or_insert_mut(source_id, ||{
1322	                        new = true;
1323	                        Default::default()
1324	                    });
1325	                    state.latest_access = Instant::now();
1326	                    if new {
1327	                        // NOTE: API does not allow both heartbeat and periodic_queries
1328	                        state.periodic_task = spawn_periodic_queries(&statesref, states.period, source_id);
1329	                        if states.global_pending_queries > 0 {
1330	                            tracing::trace!("AdvancedSubscriber{{key_expr: {}}}: Skipping heartbeat on '{}' from publisher that is currently being pulled by global query", states.key_expr, heartbeat_keyexpr);
1331	                            return;
1332	                        }
1333	                    }
1334	
1335	                    // check that it's not an old sn, and that there are no pending queries
1336	                    if (state.last_delivered.is_none()
1337	                        || state.last_delivered.is_some_and(|sn| heartbeat_sn > sn))
1338	                        && state.pending_queries == 0
1339	                    {
1340	                        let seq_num_range = seq_num_range(
1341	                            state.last_delivered.map(|s| s + 1),
1342	                            Some(heartbeat_sn),
1343	                        );
1344	
1345	                        let session = states.session.clone();
1346	                        let key_expr = states.key_expr.clone().into_owned();
1347	                        let query_target = states.query_target;
1348	                        let query_timeout = states.query_timeout;
1349	                        state.pending_queries += 1;
1350	
1351	                        tracing::trace!("AdvancedSubscriber{{key_expr: {}}}: Querying missing samples {}?{}", states.key_expr, heartbeat_keyexpr, seq_num_range);
1352	                        drop(lock);
1353	
1354	                        let handler = SequencedRepliesHandler {
1355	                            source_id,
1356	                            statesref: statesref.clone(),
1357	                        };
1358	                        let _ = session
1359	                            .get(Selector::from((heartbeat_keyexpr, seq_num_range)))
1360	                            .callback({
1361	                                move |r: Reply| {
1362	                                    if let Ok(s) = r.into_result() {
1363	                                        if key_expr.intersects(s.key_expr()) {
1364	                                            let states = &mut *zlock!(handler.statesref);
1365	                                            tracing::trace!("AdvancedSubscriber{{key_expr: {}}}: Received reply with Sample{{info:{:?}, ts:{:?}}}", states.key_expr, s.source_info(), s.timestamp());
1366	                                            handle_sample(states, s);
1367	                                        }
1368	                                    }
1369	                                }
1370	                            })
1371	                            .consolidation(ConsolidationMode::None)
1372	                            .accept_replies(ReplyKeyExpr::Any)
1373	                            .target(query_target)
1374	                            .timeout(query_timeout)
1375	                            .wait();
1376	                    }
1377	                })
1378	                .allowed_origin(conf.origin)
1379	                .wait()?;
1380	            Some(heartbeat_sub)
1381	        } else {
1382	            None
1383	        };
1384	
1385	        if conf.liveliness {
1386	            let suffix = KE_ADV_PREFIX
1387	                / KE_SUB
1388	                / &subscriber.id().zid().into_keyexpr()
1389	                / &KeyExpr::try_from(subscriber.id().eid().to_string()).unwrap();
1390	            let suffix = match meta {
1391	                Some(meta) => suffix / &meta,
1392	                // We need this empty chunk because of a routing matching bug
1393	                _ => suffix / KE_EMPTY,
1394	            };
1395	            tracing::debug!(
1396	                "AdvancedSubscriber{{key_expr: {}}}: Declare liveliness token {}",
1397	                key_expr,
1398	                &key_expr / &suffix,
1399	            );
1400	            let token = conf
1401	                .session
1402	                .liveliness()
1403	                .declare_token(&key_expr / &suffix)
1404	                .wait()?;
1405	            zlock!(statesref).token = Some(token)
1406	        }
1407	
1408	        let reliable_subscriber = AdvancedSubscriber {
1409	            statesref,
1410	            subscriber,
1411	            receiver,
1412	            liveliness_subscriber,
1413	            heartbeat_subscriber,
1414	        };
1415	
1416	        Ok(reliable_subscriber)
1417	    }
