1500	#[zenoh_macros::unstable]
1501	#[inline]
1502	fn flush_sequenced_source(
1503	    state: &mut SourceState<WrappingSn>,
1504	    callback: Option<&Callback<Sample>>,
1505	    source_id: &EntityGlobalId,
1506	    miss_handlers: &HashMap<usize, Callback<Miss>>,
1507	) {
1508	    let Some(callback) = callback else {
1509	        return;
1510	    };
1511	    if state.pending_queries == 0 && !state.pending_samples.is_empty() {
1512	        let mut pending_samples = BTreeMap::new();
1513	        std::mem::swap(&mut state.pending_samples, &mut pending_samples);
1514	        for (seq_num, sample) in pending_samples {
1515	            match state.last_delivered {
1516	                None => {
1517	                    state.last_delivered = Some(seq_num);
1518	                    callback.call(sample);
1519	                }
1520	                Some(last) if seq_num == last + 1 => {
1521	                    state.last_delivered = Some(seq_num);
1522	                    callback.call(sample);
1523	                }
1524	                Some(last) if seq_num > last + 1 => {
1525	                    tracing::warn!(
1526	                        "Sample missed: missed {} samples from {:?}.",
1527	                        seq_num - last - 1,
1528	                        source_id,
1529	                    );
1530	                    for miss_callback in miss_handlers.values() {
1531	                        miss_callback.call(Miss {
1532	                            source: *source_id,
1533	                            nb: seq_num - last - 1,
1534	                        })
1535	                    }
1536	                    state.last_delivered = Some(seq_num);
1537	                    callback.call(sample);
1538	                }
1539	                _ => {
1540	                    // duplicate
1541	                }
1542	            }
1543	        }
1544	    }
1545	}
