1547	#[zenoh_macros::unstable]
1548	#[inline]
1549	fn flush_timestamped_source(
1550	    state: &mut SourceState<Timestamp>,
1551	    callback: Option<&Callback<Sample>>,
1552	) {
1553	    let Some(callback) = callback else {
1554	        return;
1555	    };
1556	    if state.pending_queries == 0 && !state.pending_samples.is_empty() {
1557	        for (timestamp, sample) in std::mem::take(&mut state.pending_samples) {
1558	            if state
1559	                .last_delivered
1560	                .map(|last| timestamp > last)
1561	                .unwrap_or(true)
1562	            {
1563	                state.last_delivered = Some(timestamp);
1564	                callback.call(sample);
1565	            }
1566	        }
1567	    }
1568	}
