195	async fn keep_alive_task(state: Arc<GroupState>) {
196	    let mid = state.local_member.mid.clone();
197	    let evt = GroupNetEvent::KeepAlive(KeepAliveEvent { mid });
198	    let buf = bincode::serialize(&evt).unwrap();
199	    let period = state
200	        .local_member
201	        .lease
202	        .mul_f32(state.local_member.refresh_ratio);
203	    loop {
204	        tokio::time::sleep(period).await;
205	        tracing::trace!("Sending Keep Alive for: {}", &state.local_member.mid);
206	        let _ = state.group_publisher.put(buf.clone()).await;
207	    }
208	}
209	
210	async fn watchdog_task(s: Arc<GroupState>, period: Duration) {
211	    loop {
212	        tokio::time::sleep(period).await;
213	        let now = Instant::now();
214	        let mut ms = s.members.lock().await;
215	        let expired_members: Vec<OwnedKeyExpr> = ms
216	            .iter()
217	            .filter(|e| e.1 .1 < now)
218	            .map(|e| e.0.clone())
219	            .collect();
220	
221	        for e in &expired_members {
222	            tracing::debug!("Member with lease expired: {}", e);
223	            ms.remove(e);
224	        }
225	        if !expired_members.is_empty() {
226	            tracing::debug!("Other members list: {:?}", ms.keys());
227	            drop(ms);
228	            let u_evt = &*s.user_events_tx.lock().await;
229	            for e in expired_members {
230	                if let Some(tx) = u_evt {
231	                    tx.send(GroupEvent::LeaseExpired(LeaseExpiredEvent { mid: e }))
232	                        .unwrap()
233	                }
234	            }
235	        }
236	    }
237	}
