239	async fn query_handler(z: Arc<Session>, state: Arc<GroupState>) {
240	    let qres: KeyExpr = format!(
241	        "{}/{}/{}",
242	        GROUP_PREFIX, &state.gid, &state.local_member.mid
243	    )
244	    .try_into()
245	    .unwrap();
246	    tracing::debug!("Started query handler for: {}", &qres);
247	    let buf = bincode::serialize(&state.local_member).unwrap();
248	    let queryable = z.declare_queryable(&qres).await.unwrap();
249	
250	    while let Ok(query) = queryable.recv_async().await {
251	        tracing::trace!("Serving query for: {}", &qres);
252	        query.reply(qres.clone(), buf.clone()).await.unwrap();
253	    }
254	}
255	
256	async fn net_event_handler(z: Arc<Session>, state: Arc<GroupState>) {
257	    let sub = z
258	        .declare_subscriber(state.group_publisher.key_expr())
259	        .await
260	        .unwrap();
261	    while let Ok(s) = sub.recv_async().await {
262	        match bincode::deserialize_from::<ZBytesReader, GroupNetEvent>(s.payload().reader()) {
263	            Ok(evt) => match evt {
264	                GroupNetEvent::Join(je) => {
265	                    tracing::debug!("Member join: {:?}", &je.member);
266	                    let alive_till = Instant::now().add(je.member.lease);
267	                    let mut ms = state.members.lock().await;
268	                    ms.insert(je.member.mid.clone(), (je.member.clone(), alive_till));
269	                    tracing::debug!("Other members list: {:?}", ms.keys());
270	                    state.cond.notify_all();
271	                    drop(ms);
272	                    let u_evt = &*state.user_events_tx.lock().await;
273	                    if let Some(tx) = u_evt {
274	                        tx.send(GroupEvent::Join(je)).unwrap()
275	                    }
276	                }
277	                GroupNetEvent::Leave(le) => {
278	                    tracing::debug!("Member leave: {:?}", &le.mid);
279	                    let mut ms = state.members.lock().await;
280	                    ms.remove(&le.mid);
281	                    tracing::debug!("Other members list: {:?}", ms.keys());
282	                    drop(ms);
283	                    let u_evt = &*state.user_events_tx.lock().await;
284	                    if let Some(tx) = u_evt {
285	                        tx.send(GroupEvent::Leave(le)).unwrap()
286	                    }
287	                }
288	                GroupNetEvent::KeepAlive(kae) => {
289	                    tracing::debug!(
290	                        "KeepAlive from {} ({})",
291	                        &kae.mid,
292	                        if kae.mid.ne(&state.local_member.mid) {
293	                            "other"
294	                        } else {
295	                            "myself"
296	                        }
297	                    );
298	                    if kae.mid.ne(&state.local_member.mid) {
299	                        let mut mm = state.members.lock().await;
300	                        let v = mm.remove(&kae.mid);
301	                        match v {
302	                            Some((m, _)) => {
303	                                tracing::trace!("Updating leasefor: {:?}", &kae.mid);
304	                                let alive_till = Instant::now().add(m.lease);
305	                                mm.insert(m.mid.clone(), (m, alive_till));
306	                            }
307	                            None => {
308	                                tracing::debug!(
309	                                    "Received Keep Alive from unknown member: {}",
310	                                    &kae.mid
311	                                );
312	                                let qres = format!("{}/{}/{}", GROUP_PREFIX, &state.gid, kae.mid);
313	                                // @TODO: we could also send this member info
314	                                let qc = zenoh::query::ConsolidationMode::None;
315	                                tracing::trace!("Issuing Query for {}", &qres);
316	                                let receiver = z.get(&qres).consolidation(qc).await.unwrap();
317	
318	                                while let Ok(reply) = receiver.recv_async().await {
319	                                    match reply.result() {
320	                                        Ok(sample) => {
321	                                            match bincode::deserialize_from::<ZBytesReader, Member>(
322	                                                sample.payload().reader(),
323	                                            ) {
324	                                                Ok(m) => {
325	                                                    let mut expiry = Instant::now();
326	                                                    expiry = expiry.add(m.lease);
327	                                                    tracing::debug!(
328	                                                        "Received member information: {:?}",
329	                                                        &m
330	                                                    );
331	                                                    mm.insert(kae.mid.clone(), (m.clone(), expiry));
332	                                                    tracing::debug!(
333	                                                        "Other members list: {:?}",
334	                                                        mm.keys()
335	                                                    );
336	                                                    // Advertise a JoinEvent
337	                                                    let u_evt = &*state.user_events_tx.lock().await;
338	                                                    if let Some(tx) = u_evt {
339	                                                        let je = JoinEvent { member: m };
340	                                                        tx.send_async(GroupEvent::Join(je))
341	                                                            .await
342	                                                            .unwrap()
343	                                                    }
344	                                                }
345	                                                Err(e) => {
346	                                                    tracing::warn!(
347	                                                        "Unable to deserialize the Member info received: {}", e);
348	                                                }
349	                                            }
350	                                        }
351	                                        Err(e) => {
352	                                            tracing::warn!("Error received: {:?}", e);
353	                                        }
354	                                    }
355	                                }
356	                                state.cond.notify_all();
357	                            }
358	                        }
359	                    } else {
360	                        tracing::trace!("KeepAlive from Local Participant -- Ignoring");
361	                    }
362	                }
363	            },
364	            Err(e) => {
365	                tracing::warn!("Failed decoding net-event due to: {:?}", e);
366	            }
367	        }
368	    }
369	}
