371	impl Group {
372	    pub async fn join<T>(z: Arc<Session>, group: T, with: Member) -> ZResult<Group>
373	    where
374	        T: TryInto<OwnedKeyExpr>,
375	        <T as TryInto<OwnedKeyExpr>>::Error: Into<ZError>,
376	    {
377	        let group: OwnedKeyExpr = group.try_into().map_err(|e| e.into())?;
378	        if group.is_wild() {
379	            bail!("Group ID is not allowed to contain wildcards: {}", group);
380	        }
381	
382	        let event_expr = format!("{GROUP_PREFIX}/{group}/{EVENT_POSTFIX}");
383	        let publisher = z
384	            .declare_publisher(event_expr)
385	            .priority(with.priority)
386	            .await
387	            .unwrap();
388	        let state = Arc::new(GroupState {
389	            gid: String::from(group),
390	            local_member: with.clone(),
391	            members: Mutex::new(Default::default()),
392	            group_publisher: publisher,
393	            user_events_tx: Mutex::new(Default::default()),
394	            cond: Condition::new(),
395	        });
396	        let is_auto_liveliness = matches!(with.liveliness, MemberLiveliness::Auto);
397	
398	        // announce the member:
399	        tracing::debug!("Sending Join Message for local member: {:?}", &with);
400	        let join_evt = GroupNetEvent::Join(JoinEvent { member: with });
401	        let buf = bincode::serialize(&join_evt).unwrap();
402	        let _ = state.group_publisher.put(buf).await;
403	
404	        let task_controller = TaskController::default();
405	        // If the liveliness is manual it is the user who has to assert it.
406	        if is_auto_liveliness {
407	            task_controller.spawn_abortable(keep_alive_task(state.clone()));
408	        }
409	        task_controller.spawn_abortable(net_event_handler(z.clone(), state.clone()));
410	        task_controller.spawn_abortable(query_handler(z.clone(), state.clone()));
411	        task_controller.spawn_abortable(watchdog_task(state.clone(), Duration::from_secs(1)));
412	        Ok(Group {
413	            state,
414	            task_controller,
415	        })
416	    }
417	
418	    /// Returns a receivers that will allow to receive notifications for group events.
419	    /// Notice that there can be a single subscription at the time, each call to subscribe
420	    /// will cancel the previous subscription.
421	    pub async fn subscribe(&self) -> Receiver<GroupEvent> {
422	        let (tx, rx) = flume::unbounded();
423	        *self.state.user_events_tx.lock().await = Some(tx);
424	        rx
425	    }
426	
427	    /// Returns the group identifier.
428	    pub fn group_id(&self) -> &str {
429	        &self.state.gid
430	    }
431	
432	    /// Returns this member identifier.
433	    pub fn local_member_id(&self) -> &str {
434	        &self.state.local_member.mid
435	    }
436	
437	    /// Returns the current group view, in other terms the list
438	    /// of group members.
439	    pub async fn view(&self) -> Vec<Member> {
440	        let mut ms: Vec<Member> = self
441	            .state
442	            .members
443	            .lock()
444	            .await
445	            .iter()
446	            .map(|e| e.1 .0.clone())
447	            .collect();
448	        ms.push(self.state.local_member.clone());
449	        ms
450	    }
451	
452	    /// Wait for a view size to be established or times out. The resulting selector parameters
453	    /// indicates whether the desired view size has been established.
454	    pub async fn wait_for_view_size(&self, size: usize, timeout: Duration) -> bool {
455	        if self.state.members.lock().await.len() + 1 >= size {
456	            true
457	        } else {
458	            // let s = self.state.clone();
459	            let f = async {
460	                loop {
461	                    let ms = self.state.members.lock().await;
462	                    if ms.len() + 1 >= size {
463	                        return true;
464	                    } else {
465	                        self.state.cond.wait(ms).await;
466	                    }
467	                }
468	            };
469	            let r: bool = select! {
470	                p = f.fuse() => p,
471	                _ = tokio::time::sleep(timeout).fuse() => false,
472	            };
473	            r
474	        }
475	    }
476	
477	    /// Returns the current group size.
478	    pub async fn size(&self) -> usize {
479	        let ms = self.state.members.lock().await;
480	        ms.len() + 1 // with +1 being the local member
481	    }
482	
483	    /// Returns the evental leader for this group. Notice that a view change may cause
484	    /// a change on leader. Thus it is wise to always get the leader after a view change.
485	    pub async fn leader(&self) -> Member {
486	        use std::cmp::Ordering;
487	        let group = self.view().await;
488	        let mut leader = self.state.local_member.clone();
489	        for m in group {
490	            if leader.id().as_str().cmp(m.id().as_str()) == Ordering::Less {
491	                leader = m
492	            }
493	        }
494	        leader
495	    }
496	}
