16	use clap::Parser;
17	use zenoh::{bytes::Encoding, key_expr::KeyExpr, Config};
18	use zenoh_examples::CommonArgs;
19	
20	#[tokio::main]
21	async fn main() {
22	    // Initiate logging
23	    zenoh::init_log_from_env_or("error");
24	
25	    let (config, key_expr, payload, attachment, add_matching_listener) = parse_args();
26	
27	    println!("Opening session...");
28	    let session = zenoh::open(config).await.unwrap();
29	
30	    println!("Declaring Publisher on '{key_expr}'...");
31	    let publisher = session.declare_publisher(&key_expr).await.unwrap();
32	
33	    if add_matching_listener {
34	        publisher
35	            .matching_listener()
36	            .callback(|matching_status| {
37	                if matching_status.matching() {
38	                    println!("Publisher has matching subscribers.");
39	                } else {
40	                    println!("Publisher has NO MORE matching subscribers.");
41	                }
42	            })
43	            .background()
44	            .await
45	            .unwrap();
46	    }
47	
48	    println!("Press CTRL-C to quit...");
49	    for idx in 0..u32::MAX {
50	        tokio::time::sleep(Duration::from_secs(1)).await;
51	        let buf = format!("[{idx:4}] {payload}");
52	        println!("Putting Data ('{}': '{}')...", &key_expr, buf);
53	        // Refer to z_bytes.rs to see how to serialize different types of message
54	        publisher
55	            .put(buf)
56	            .encoding(Encoding::TEXT_PLAIN) // Optionally set the encoding metadata 
57	            .attachment(attachment.clone()) // Optionally add an attachment
58	            .await
59	            .unwrap();
60	    }
61	}
