14	use std::time::Duration;
15	
16	use clap::Parser;
17	use zenoh::{
18	    query::{QueryTarget, Selector},
19	    Config,
20	};
21	use zenoh_examples::CommonArgs;
22	
23	#[tokio::main]
24	async fn main() {
25	    // initiate logging
26	    zenoh::init_log_from_env_or("error");
27	
28	    let (config, selector, payload, target, timeout) = parse_args();
29	
30	    println!("Opening session...");
31	    let session = zenoh::open(config).await.unwrap();
32	
33	    println!("Sending Query '{selector}'...");
34	    let mut builder = session
35	        .get(&selector)
36	        // // By default get receives replies from a FIFO.
37	        // // Uncomment this line to use a ring channel instead.
38	        // // More information on the ring channel are available in the z_pull example.
39	        // .with(zenoh::handlers::RingChannel::default())
40	        // Refer to z_bytes.rs to see how to serialize different types of message
41	        .target(target)
42	        .timeout(timeout);
43	    if let Some(payload) = payload {
44	        builder = builder.payload(payload);
45	    }
46	    let replies = builder.await.unwrap();
47	    while let Ok(reply) = replies.recv_async().await {
48	        match reply.result() {
49	            Ok(sample) => {
50	                // Refer to z_bytes.rs to see how to deserialize different types of message
51	                let payload = sample
52	                    .payload()
53	                    .try_to_string()
54	                    .unwrap_or_else(|e| e.to_string().into());
55	                println!(
56	                    ">> Received ('{}': '{}')",
57	                    sample.key_expr().as_str(),
58	                    payload,
59	                );
60	            }
61	            Err(err) => {
62	                let payload = err
63	                    .payload()
64	                    .try_to_string()
65	                    .unwrap_or_else(|e| e.to_string().into());
66	                println!(">> Received (ERROR: '{payload}')");
67	            }
68	        }
69	    }
70	}
