72	#[derive(clap::ValueEnum, Clone, Copy, Debug)]
73	#[value(rename_all = "SCREAMING_SNAKE_CASE")]
74	enum Qt {
75	    BestMatching,
76	    All,
77	    AllComplete,
78	}
79	
80	#[derive(Parser, Clone, Debug)]
81	struct Args {
82	    #[arg(short, long, default_value = "demo/example/**")]
83	    /// The selection of resources to query
84	    selector: Selector<'static>,
85	    #[arg(short, long)]
86	    /// An optional payload to put in the query.
87	    payload: Option<String>,
88	    #[arg(short, long, default_value = "BEST_MATCHING")]
89	    /// The target queryables of the query.
90	    target: Qt,
91	    #[arg(short = 'o', long, default_value = "10000")]
92	    /// The query timeout in milliseconds.
93	    timeout: u64,
94	    #[command(flatten)]
95	    common: CommonArgs,
96	}
97	
98	fn parse_args() -> (
99	    Config,
100	    Selector<'static>,
101	    Option<String>,
102	    QueryTarget,
103	    Duration,
104	) {
105	    let args = Args::parse();
106	    (
107	        args.common.into(),
108	        args.selector,
109	        args.payload,
110	        match args.target {
111	            Qt::BestMatching => QueryTarget::BestMatching,
112	            Qt::All => QueryTarget::All,
113	            Qt::AllComplete => QueryTarget::AllComplete,
114	        },
115	        Duration::from_millis(args.timeout),
116	    )
117	}
